//! build-residual-dict — offline tool to build a bw-codec dictionary
//! from captured residuals.
//!
//! Usage:
//!   build-residual-dict --input dir-of-bwmr-files [--input file2.bwmr ...]
//!                       --output output.bwdict
//!                       [--max-entries 4096] [--entry-len 64]
//!                       [--layer-filter 0,1,2,...] [--seed 0xCAFE]
//!
//! BWMR record format (mirrors Agent A's capture sink):
//!   u16  layer_idx          (LE)
//!   u32  seq_idx            (LE)
//!   u32  hidden_dim         (LE)
//!   u64  timestamp          (LE)
//!   f32[hidden_dim]         (LE byte order, raw IEEE-754)
//! Header length = 2 + 4 + 4 + 8 = 18 bytes; payload = hidden_dim * 4 bytes.
//! Records are concatenated back-to-back, one BWMR file may contain many.
//!
//! .bwdict output framing:
//!   u32  magic         = b"BWDC"          (literal ASCII, NOT a LE int)
//!   u32  version       = 0x00000001 LE
//!   u32  entry_count   LE
//!   u32  entry_len     LE
//!   entry_count * entry_len bytes of dictionary payload (top-N windows).
//!
//! Strategy:
//!   1. Stream every captured residual byte stream from the input files.
//!   2. Slice each into fixed-length windows of `entry_len` bytes
//!      (chunks_exact — trailing tail bytes are dropped).
//!   3. Count window frequency via a HashMap<Vec<u8>, u64>.
//!   4. Sort descending by frequency, truncate to `max_entries`, emit
//!      the .bwdict frame.
//!
//! No external deps beyond std + bytemuck (bytemuck unused for now — kept
//! in-scope because the natural follow-on is to cast f32 -> u8 windows
//! with bytemuck::cast_slice when we move from raw bytes to bucketed
//! residual signatures).

use std::collections::HashMap;
use std::fs::{self, File};
use std::io::{BufReader, Read, Write};
use std::path::{Path, PathBuf};
use std::process::ExitCode;

const BWMR_HEADER_LEN: usize = 18;
const BWDICT_MAGIC: &[u8; 4] = b"BWDC";
const BWDICT_VERSION: u32 = 1;

const DEFAULT_MAX_ENTRIES: usize = 4096;
const DEFAULT_ENTRY_LEN: usize = 64;
const DEFAULT_SEED: u64 = 0xCAFE;

struct Args {
    inputs: Vec<PathBuf>,
    output: PathBuf,
    max_entries: usize,
    entry_len: usize,
    layer_filter: Option<Vec<u16>>,
    #[allow(dead_code)] // reserved for reservoir-sampling follow-on.
    seed: u64,
}

fn main() -> ExitCode {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            eprintln!("[build-residual-dict] error: {e}");
            eprintln!();
            print_usage();
            return ExitCode::from(2);
        }
    };

    if args.entry_len == 0 {
        eprintln!("[build-residual-dict] error: --entry-len must be > 0");
        return ExitCode::from(2);
    }
    if args.max_entries == 0 {
        eprintln!("[build-residual-dict] error: --max-entries must be > 0");
        return ExitCode::from(2);
    }

    // Expand input arguments: each --input may name a directory (walk one
    // level deep, taking files ending in `.bwmr`) or a single file.
    let resolved_inputs = match resolve_inputs(&args.inputs) {
        Ok(v) => v,
        Err(e) => {
            eprintln!("[build-residual-dict] resolve inputs failed: {e}");
            return ExitCode::from(2);
        }
    };

    if resolved_inputs.is_empty() {
        eprintln!("[build-residual-dict] no .bwmr inputs found");
        return ExitCode::from(2);
    }

    let mut window_counts: HashMap<Vec<u8>, u64> = HashMap::new();
    let mut total_records: u64 = 0;
    let mut total_windows: u64 = 0;

    for input in &resolved_inputs {
        match ingest_bwmr_file(
            input,
            args.entry_len,
            &args.layer_filter,
            &mut window_counts,
        ) {
            Ok((recs, wins)) => {
                total_records += recs;
                total_windows += wins;
                eprintln!(
                    "[build-residual-dict]   {} → {} records, {} windows",
                    input.display(),
                    recs,
                    wins
                );
            }
            Err(e) => {
                eprintln!(
                    "[build-residual-dict] warn: skipping {} ({})",
                    input.display(),
                    e
                );
            }
        }
    }

    // Sort by frequency descending, take top max_entries.
    let mut entries: Vec<(Vec<u8>, u64)> = window_counts.into_iter().collect();
    entries.sort_by(|a, b| b.1.cmp(&a.1));
    entries.truncate(args.max_entries);

    let dict = build_bwdict(args.entry_len, &entries);
    let mut out = match File::create(&args.output) {
        Ok(f) => f,
        Err(e) => {
            eprintln!(
                "[build-residual-dict] open output {} failed: {}",
                args.output.display(),
                e
            );
            return ExitCode::from(1);
        }
    };
    if let Err(e) = out.write_all(&dict) {
        eprintln!("[build-residual-dict] write output failed: {e}");
        return ExitCode::from(1);
    }

    eprintln!(
        "[build-residual-dict] wrote {} entries × {} bytes to {} (from {} records, {} windows)",
        entries.len(),
        args.entry_len,
        args.output.display(),
        total_records,
        total_windows,
    );
    ExitCode::SUCCESS
}

fn print_usage() {
    eprintln!(
        "usage: build-residual-dict --input <path> [--input <path> ...] --output <file.bwdict>"
    );
    eprintln!("                          [--max-entries N] [--entry-len N]");
    eprintln!("                          [--layer-filter 0,1,2,...] [--seed 0xCAFE]");
}

fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = std::env::args().skip(1).collect();
    let mut inputs: Vec<PathBuf> = Vec::new();
    let mut output: Option<PathBuf> = None;
    let mut max_entries = DEFAULT_MAX_ENTRIES;
    let mut entry_len = DEFAULT_ENTRY_LEN;
    let mut layer_filter: Option<Vec<u16>> = None;
    let mut seed: u64 = DEFAULT_SEED;

    let mut i = 0;
    while i < argv.len() {
        let arg = &argv[i];
        match arg.as_str() {
            "--input" | "-i" => {
                let v = argv
                    .get(i + 1)
                    .ok_or_else(|| format!("{arg} requires a value"))?;
                inputs.push(PathBuf::from(v));
                i += 2;
            }
            "--output" | "-o" => {
                let v = argv
                    .get(i + 1)
                    .ok_or_else(|| format!("{arg} requires a value"))?;
                output = Some(PathBuf::from(v));
                i += 2;
            }
            "--max-entries" => {
                let v = argv
                    .get(i + 1)
                    .ok_or_else(|| format!("{arg} requires a value"))?;
                max_entries = v
                    .parse::<usize>()
                    .map_err(|e| format!("--max-entries: {e}"))?;
                i += 2;
            }
            "--entry-len" => {
                let v = argv
                    .get(i + 1)
                    .ok_or_else(|| format!("{arg} requires a value"))?;
                entry_len = v
                    .parse::<usize>()
                    .map_err(|e| format!("--entry-len: {e}"))?;
                i += 2;
            }
            "--layer-filter" => {
                let v = argv
                    .get(i + 1)
                    .ok_or_else(|| format!("{arg} requires a value"))?;
                let parsed: Result<Vec<u16>, _> =
                    v.split(',').map(|s| s.trim().parse::<u16>()).collect();
                layer_filter = Some(parsed.map_err(|e| format!("--layer-filter: {e}"))?);
                i += 2;
            }
            "--seed" => {
                let v = argv
                    .get(i + 1)
                    .ok_or_else(|| format!("{arg} requires a value"))?;
                // Accept 0x… hex or plain decimal.
                let parsed =
                    if let Some(hex) = v.strip_prefix("0x").or_else(|| v.strip_prefix("0X")) {
                        u64::from_str_radix(hex, 16)
                    } else {
                        v.parse::<u64>()
                    };
                seed = parsed.map_err(|e| format!("--seed: {e}"))?;
                i += 2;
            }
            "--help" | "-h" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown argument: {other}")),
        }
    }

    if inputs.is_empty() {
        return Err("at least one --input is required".to_string());
    }
    let output = output.ok_or_else(|| "--output is required".to_string())?;

    Ok(Args {
        inputs,
        output,
        max_entries,
        entry_len,
        layer_filter,
        seed,
    })
}

/// Expand --input arguments: each path is either a single file or a
/// directory we walk one level deep collecting `*.bwmr` entries.
fn resolve_inputs(paths: &[PathBuf]) -> std::io::Result<Vec<PathBuf>> {
    let mut out: Vec<PathBuf> = Vec::new();
    for p in paths {
        let md = fs::metadata(p)?;
        if md.is_dir() {
            for entry in fs::read_dir(p)? {
                let entry = entry?;
                let path = entry.path();
                if path.is_file() && path.extension().and_then(|s| s.to_str()) == Some("bwmr") {
                    out.push(path);
                }
            }
        } else if md.is_file() {
            out.push(p.clone());
        }
    }
    out.sort();
    Ok(out)
}

/// Stream one BWMR file, slicing each residual payload into
/// `entry_len`-byte windows and bumping the count map. Returns
/// `(records_read, windows_counted)`.
fn ingest_bwmr_file(
    path: &Path,
    entry_len: usize,
    layer_filter: &Option<Vec<u16>>,
    counts: &mut HashMap<Vec<u8>, u64>,
) -> std::io::Result<(u64, u64)> {
    let file = File::open(path)?;
    let mut reader = BufReader::new(file);
    let mut header = [0u8; BWMR_HEADER_LEN];
    let mut records: u64 = 0;
    let mut windows: u64 = 0;

    loop {
        match reader.read_exact(&mut header) {
            Ok(_) => {}
            Err(ref e) if e.kind() == std::io::ErrorKind::UnexpectedEof => break,
            Err(e) => return Err(e),
        }
        let layer_idx = u16::from_le_bytes([header[0], header[1]]);
        let _seq_idx = u32::from_le_bytes([header[2], header[3], header[4], header[5]]);
        let hidden_dim = u32::from_le_bytes([header[6], header[7], header[8], header[9]]) as usize;
        let _ts = u64::from_le_bytes([
            header[10], header[11], header[12], header[13], header[14], header[15], header[16],
            header[17],
        ]);

        let payload_len = hidden_dim.saturating_mul(4);
        let mut payload = vec![0u8; payload_len];
        reader.read_exact(&mut payload)?;
        records += 1;

        if let Some(ref allowed) = layer_filter {
            if !allowed.contains(&layer_idx) {
                continue;
            }
        }

        for window in payload.chunks_exact(entry_len) {
            *counts.entry(window.to_vec()).or_insert(0) += 1;
            windows += 1;
        }
    }

    Ok((records, windows))
}

/// Frame the top-N windows into the `.bwdict` wire layout.
fn build_bwdict(entry_len: usize, entries: &[(Vec<u8>, u64)]) -> Vec<u8> {
    let header_len = 4 + 4 + 4 + 4;
    let payload_len = entries.len() * entry_len;
    let mut out = Vec::with_capacity(header_len + payload_len);
    out.extend_from_slice(BWDICT_MAGIC); // magic = b"BWDC"
    out.extend_from_slice(&BWDICT_VERSION.to_le_bytes());
    out.extend_from_slice(&(entries.len() as u32).to_le_bytes());
    out.extend_from_slice(&(entry_len as u32).to_le_bytes());
    for (window, _count) in entries {
        // Defensive: windows in `counts` came from chunks_exact, so every
        // one is exactly `entry_len` bytes — but truncate/pad here to keep
        // the file framing invariant locally enforced.
        if window.len() == entry_len {
            out.extend_from_slice(window);
        } else if window.len() > entry_len {
            out.extend_from_slice(&window[..entry_len]);
        } else {
            out.extend_from_slice(window);
            out.extend(std::iter::repeat_n(0u8, entry_len - window.len()));
        }
    }
    out
}
